-- Enrichment marathon batch: CASEpeer, Castopod, Castos, Celoxis, Centrifugo, Ceph, Cerbos, Chameleon

-- ── CASEpeer ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CASEpeer is cloud-based case management software built for personal injury law firms, covering intake, documents, medical treatment tracking, and settlements.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$79/user/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Irvine, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CASEpeer Review 2026: Features & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$CASEpeer is personal injury case management software with intake, document, and settlement tools. Compare 2026 pricing tiers, features, pros, and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CASEpeer is a cloud-based legal case management platform purpose-built for personal injury law firms, founded in 2015 by Darren Fancher and headquartered in Irvine, California. The software consolidates the personal injury case lifecycle — client intake, document management, medical treatment tracking, case timelines, settlement negotiation, and client communication — into a single web-based system hosted on Amazon Web Services. CASEpeer is sold on a per-user, per-month subscription with no long-term contract or setup fee, priced across three tiers: Basic at $79/user/month, Pro at $119/user/month, and Advanced at $149/user/month. The Basic tier covers core case tracking, document storage, and calendaring. The Pro tier adds an online intake management workflow, SMS texting with clients, integration support, and access to more than 50 built-in reports. The Advanced tier layers on text-message appointment scheduling, an office-wide reporting suite, a branded client intake portal, two-way data synchronization, and a proprietary Case Grades scoring feature that flags case health and settlement readiness. Across all tiers, CASEpeer includes a secure client portal, online intake forms, eSignature collection, and built-in legal AI functionality for drafting, summarizing, and editing case documents. Because the platform is scoped specifically to plaintiff-side personal injury practice rather than general legal practice management, its data model is organized around medical providers, treatment timelines, liens, and settlement/demand workflows rather than generic matter types, billing codes, or court-calendar rules used by firms in other practice areas. This specialization is CASEpeer's core differentiator versus general-purpose legal practice management tools such as Clio or MyCase, which support broader practice areas but lack purpose-built personal injury workflows like treatment tracking and settlement calculators. CASEpeer operates as part of the 8am family of legal-technology products and provides support by phone, chat, and email, along with free onboarding and ongoing training for firm staff. Typical customers are small-to-midsize personal injury law firms and plaintiff attorneys who need to manage high case volumes with consistent intake, documentation, and settlement processes across paralegals, case managers, and attorneys. Because pricing is per named user rather than per case or per firm, costs scale directly with headcount, making CASEpeer better suited to firms with a defined caseload team than solo practitioners handling occasional personal injury matters. The absence of a public free trial or freemium tier means prospective customers typically evaluate the platform through a scheduled demo before committing to a subscription. Overall, CASEpeer positions itself as a specialist alternative to horizontal legal case management software, trading broad practice-area coverage for deep personal injury workflow automation, AI-assisted documentation, and reporting built around settlement outcomes.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2daef1f5-cac7-42ef-aa09-bc9e2945a78a';

