-- ── Castopod ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Castopod is a free, open-source podcast hosting platform with built-in ActivityPub/Fediverse integration and Podcasting 2.0 features, self-hostable or hosted.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Castopod Review: Open-Source Podcast Hosting$q$, seo_title),
  seo_meta_description = COALESCE($q$Castopod is free, open-source podcast hosting software with ActivityPub, Podcasting 2.0 support, and self-hosting. See features, pricing, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Castopod is a free and open-source podcast hosting platform created by the French company Ad Aures, first released around 2020 and licensed under the GNU Affero General Public License (AGPL-3.0). It is built on the CodeIgniter4 PHP framework and can be self-hosted on a server the podcaster controls, or run through third-party one-click hosting providers such as Elestio, Cloudron, and Klutch. Castopod's defining feature is that it is one of the only podcast hosts that combines full Podcasting 2.0 support with native ActivityPub (Fediverse) integration: every podcast Castopod hosts is automatically also a Fediverse account, so users on Mastodon, Pixelfed, or other ActivityPub-compatible networks can follow a show, and listeners can comment on individual episodes with replies that federate across the network the same way a social media reply does. On the Podcasting 2.0 side, Castopod supports the modern RSS namespace tags that newer podcast apps read, including persistent GUIDs, locked feeds, transcripts, funding links, chapters, episode location tags, contributor/person tags, and soundbites, letting shows take advantage of features supported by apps like Podcast Addict, Fountain, and Podverse in addition to legacy players. Castopod distributes episodes to all major indexes and directories, including Apple Podcasts, Spotify, Google Podcasts, Deezer, and the Podcast Index, and includes built-in analytics for tracking downloads and audience behavior. Because it is open source, podcasters who self-host Castopod keep full ownership of and control over their media files, RSS feed, and listener data, and can extend the platform's behavior through its plugin system rather than depending on a third-party host's roadmap. Ad Aures also operates Castopod.com, a managed hosting option for podcasters who want the software without running their own server; that service includes a set number of free downloads per plan with additional storage billed at a small usage-based rate (around €0.06 per GB), and users can bring their own domain or use a free subdomain. Because the core software has no license fee, Castopod's real cost for self-hosters is server infrastructure or a third-party host's usage-based fee rather than a subscription to Castopod itself, making it attractive to podcasters and networks comfortable with basic server administration, or who use a managed open-source hosting provider and want to avoid vendor lock-in with a proprietary host. It is best suited to independent podcasters and open-source-minded creators who value Fediverse distribution and data ownership over the polish and customer support of a fully managed commercial hosting product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9de517df-9167-4f74-81ef-57b4e421d271';

