-- ── Castos ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Castos is a podcast hosting platform for creators and agencies offering unlimited downloads, WordPress integration, YouTube republishing, and private podcasts.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$19/month$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Castos Review 2026: Pricing, Features & Plans$q$, seo_title),
  seo_meta_description = COALESCE($q$Castos is podcast hosting software with unlimited downloads, WordPress publishing, and YouTube republishing. Compare 2026 pricing, features, and plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Castos is a podcast hosting platform founded by Craig Hewitt around 2016 as a bootstrapped company that grew out of the WordPress podcasting plugin ecosystem. It offers unlimited podcast hosting with no storage caps or per-download overage fees, positioning itself against usage-limited competitors by charging a flat monthly rate per tier regardless of how many episodes or shows a customer publishes. Castos' four subscription tiers are Essentials at $19/month (up to 100 private subscribers, roughly 20,000 monthly downloads, and 10 monthly transcription credits), Growth at $49/month (up to 250 private subscribers, about 75,000 monthly downloads, 25 transcription credits, YouTube republishing, and Headliner integration for creating audiogram social clips), Pro at $99/month (up to 500 private subscribers, roughly 200,000 monthly downloads, 100 transcription credits, and video file hosting), and Castos Premium at $499/month, which adds custom contracts and invoicing, single sign-on, higher usage limits, and a dedicated account manager. All paid plans include a 14-day free trial. Castos' core differentiator is its deep WordPress integration: the company maintains the Seriously Simple Podcasting plugin, which lets podcasters publish episodes directly from their WordPress dashboard rather than a separate hosting-platform interface, and Castos also offers a dedicated hosting-for-agencies program for teams managing podcasts on behalf of multiple clients. Beyond WordPress publishing, Castos automatically distributes episodes to Apple Podcasts, Spotify, YouTube, and other major directories, provides detailed audience analytics covering listener location, device, and playback duration per episode, and includes a customizable podcast website builder that does not require design or development work. Castos also supports private podcast feeds, used by companies and course creators for internal communications, employee onboarding, and gated paid content distributed outside the public podcast directories. An AI Assistant feature automatically generates show notes, episode titles, social media posts, and chapter markers from uploaded audio, reducing post-production workload for solo creators and small teams. Castos operates as a fully remote, distributed company, which is reflected in inconsistent public records of a single legal headquarters. Castos is best suited to podcasters and podcasting agencies who want a hosting platform without download-based overage fees, who publish through WordPress, or who need private/internal podcast feeds — as opposed to creators who want the lowest possible entry price, where flat-rate competitors with cheaper starting tiers may be more cost-effective at very low download volumes.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1be06e6f-80c4-4800-be23-0b5ae2f639dd';

