-- ── Centrifugo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Centrifugo is an open-source, self-hosted real-time messaging server for WebSocket, SSE, and streaming APIs, used as an alternative to Pusher and PubNub.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Centrifugo Review: Real-Time Messaging Server$q$, seo_title),
  seo_meta_description = COALESCE($q$Centrifugo is an open-source, self-hosted real-time messaging server supporting WebSocket, SSE, and gRPC. See features, licensing, and PRO options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Centrifugo is an open-source, self-hosted real-time messaging server created by developer Alexander Emelin under the Centrifugal Labs project, with roots going back to an earlier Python-based tool called Centrifuge around 2012 before being rewritten in Go and established as Centrifugo around 2015. It is positioned as a self-hosted alternative to hosted real-time messaging services such as Pusher, Ably, PubNub, and Socket.IO, and to framework-native solutions like Phoenix.PubSub or SignalR, for teams that want to run their own real-time infrastructure instead of depending on a third-party API. Centrifugo is written in Go and released under the Apache 2.0 license, and it exposes a channel-based publish/subscribe model over multiple transport protocols, including WebSocket, HTTP-streaming, Server-Sent Events, WebTransport, and gRPC, so client applications can choose whichever transport best fits their environment. It provides flexible authentication, several subscription models, channel history and automatic stream recovery after disconnects, online presence tracking, delta-compressed updates to reduce bandwidth, and the ability to proxy connection and subscription events back to an application's own backend for custom authorization logic. For horizontal scaling, Centrifugo coordinates state across a cluster using Redis (including Redis Cluster or Redis-compatible stores like AWS ElastiCache, Valkey, KeyDB, or DragonflyDB), PostgreSQL, or NATS, and the project states that a single modern server running Centrifugo can handle roughly one million concurrent WebSocket connections and around thirty million delivered messages per minute. Official client SDKs are available for JavaScript (browser and Node.js), React Native, Dart/Flutter, Swift, Java, Python, Go, and .NET, making it usable from web, mobile, and backend applications alike. Typical use cases include chat applications, live comment feeds, multiplayer game state synchronization, real-time dashboards and data visualizations, collaborative editing tools, and streaming partial responses from AI/LLM systems to a client as they are generated. Centrifugo has been used in production for roughly a decade by companies including VK, Badoo, ManyChat, OpenWeb, and Grafana, giving it a track record of handling large-scale real-time traffic outside of small hobby deployments. Alongside the free, Apache-2.0-licensed core server, Centrifugal Labs also offers Centrifugo PRO, a paid edition with additional enterprise-oriented capabilities; PRO pricing is not publicly listed and is provided on a custom basis. Because Centrifugo is infrastructure software rather than an end-user application, adopting it requires engineering effort to deploy, configure, and integrate with an application's authentication and backend systems, which makes it best suited to development teams building real-time features into their own products rather than non-technical users looking for a plug-and-play notification service.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1c38ae10-51dd-4efa-aae5-4c2f20863745';

