-- ── Ceph ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Ceph is a free, open-source, software-defined storage platform providing unified object, block, and file storage across distributed commodity hardware.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Ceph Storage Review: Features & Open-Source Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Ceph is open-source, software-defined storage offering unified object, block, and file storage. Learn about features, licensing, and Red Hat support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Ceph is a free and open-source, software-defined storage platform that provides unified object, block, and file storage from a single distributed cluster built on commodity hardware. It originated as the doctoral research project of Sage Weil at the University of California, Santa Cruz, and was first open-sourced in 2006 under the GNU Lesser General Public License (LGPL 2.1). Early development was supported first by Lawrence Livermore National Laboratory and then by DreamHost, the web hosting company Weil co-founded, before Weil co-founded Inktank Storage in 2011 to provide professional services and support around Ceph. Red Hat acquired Inktank in 2014 for approximately $175 million and has since driven the majority of Ceph's core development, packaging an enterprise-supported distribution as Red Hat Ceph Storage while the underlying project remains open source and community-governed through the Ceph Foundation under the Linux Foundation. Architecturally, Ceph is designed with no single point of failure: data is distributed and replicated (or protected with erasure coding) across cluster nodes using the CRUSH placement algorithm, which calculates data location deterministically rather than relying on a central metadata lookup for every operation, allowing the system to scale to exabyte-level capacity. Since the Luminous release (version 12), Ceph has used its own storage backend, BlueStore, to manage raw block devices directly rather than relying on a conventional filesystem underneath it, improving performance and reducing overhead. Ceph exposes three storage interfaces from the same cluster: RADOS Gateway (RGW) for S3- and Swift-compatible object storage, RADOS Block Device (RBD) for block storage commonly used as backing storage for virtual machines and containers, and CephFS, a POSIX-compliant distributed file system. The system is described as self-healing and self-managing, automatically detecting and recovering from node or disk failures and rebalancing data across the cluster with minimal manual administration. Ceph is widely used as the storage layer underneath OpenStack clouds and Kubernetes persistent-volume implementations via the Rook operator, and by organizations that need software-defined storage they can run on standard servers rather than proprietary storage appliances. Because Ceph is free and open source, the software itself has no license cost, but running it in production requires either in-house expertise to deploy, tune, and operate a distributed storage cluster, or a paid support subscription such as Red Hat Ceph Storage, whose pricing is not publicly listed and is quoted directly by Red Hat. Ceph is best suited to organizations — cloud providers, research institutions, and enterprises running private or hybrid clouds — that need petabyte-to-exabyte-scale storage with commodity hardware economics rather than small teams needing simple file storage.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '32f17210-2418-4e31-bedc-836e12407246';

