-- ── Cerbos ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cerbos is an open-source, language-agnostic authorization engine that lets developers define and enforce access-control policies outside application code.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (PDP open source); Hub from $25/month$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cerbos Review: Open-Source Authorization Engine$q$, seo_title),
  seo_meta_description = COALESCE($q$Cerbos is an open-source authorization engine for RBAC, ABAC, and ReBAC policies. See features, Cerbos Hub pricing, and how it compares to OPA.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cerbos is an open-source, language-agnostic authorization engine founded in 2021 by Emre Baran, Alex Olivier, and Charith Ellawala, and headquartered in London, United Kingdom. The company has raised roughly $11-15 million in funding from investors including OMERS Ventures and Crane Venture Partners. Cerbos lets development teams externalize access-control logic from their application code: instead of hard-coding permission checks throughout a codebase, teams write authorization policies in YAML that define who can perform which actions on which resources, and the Cerbos Policy Decision Point (PDP) evaluates those policies against incoming requests and returns an allow/deny decision. The PDP is open source under the Apache 2.0 license, free to run indefinitely on any infrastructure, and built in Go for stateless, horizontally scalable deployment with sub-millisecond decision latency. Cerbos supports the major access-control models out of the box, including role-based access control (RBAC), attribute-based access control (ABAC), relationship-based access control (ReBAC), and general policy-based access control (PBAC), and ships official SDKs for eight languages: Go, Java, JavaScript, Python, .NET, PHP, Ruby, and Rust. On top of the free PDP, Cerbos sells Cerbos Hub, a commercial control plane for policy authoring, testing, versioning, distribution, and audit visibility, following an open-core business model. Cerbos Hub is priced in four tiers: a free Proof of Concept tier covering up to 100 monthly active principals with two simultaneous PDPs and one week of audit log retention; a Development tier starting at $25/month with a three-month free trial, covering the first 100 monthly active principals with expanded workspace, PDP, and audit-log limits; a Production tier starting at $933/month covering the first 5,000 monthly active principals with unlimited workspaces, PDPs, and tenants plus one-year audit-log retention and an uptime SLA; and a custom-priced Enterprise tier adding SSO, self-hosted Hub deployment options, extended audit retention, and dedicated training. Cerbos also offers Synapse, a data-enrichment layer that fetches identity, resource, and relationship data from external systems to enrich authorization requests and translate infrastructure protocols into Cerbos policy checks — relevant for teams giving AI agents scoped, auditable access to internal systems. According to Cerbos, the platform processes more than 1.2 billion authorization checks per month across its user base. Cerbos is best suited to engineering teams building applications with complex, evolving permission requirements — multi-tenant SaaS products, systems needing fine-grained per-resource access control, or applications governing what AI agents are allowed to access — who want authorization logic managed and audited separately from application code rather than scattered through if/else permission checks.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '62db09f8-596e-4759-92a2-df735f8464c1';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '62db09f8-596e-4759-92a2-df735f8464c1' AND logo IS NULL AND website IS NOT NULL;

