-- ── Chameleon ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chameleon is a no-code digital adoption platform for building in-app product tours, tooltips, banners, and surveys to drive user onboarding and engagement.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (HelpBar); paid plans from $279/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$~100 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chameleon Review 2026: Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Chameleon is a no-code product adoption platform for in-app tours, tooltips, and surveys. Compare 2026 pricing plans, features, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chameleon is a no-code digital adoption platform for building in-app user experiences, founded in 2015 by Pulkit Agrawal and Brian Norton and headquartered in San Francisco, California. The platform lets product, marketing, and customer success teams build and launch in-app tours, tooltips, hotspots, announcement banners, checklists, and microsurveys without writing code or waiting on engineering resources, targeting common product-led-growth use cases like user onboarding, feature adoption, upsell prompts, and in-product feedback collection. Chameleon's building blocks include an embeddable component system for placing interactive UI elements anywhere in a product's interface, native NPS and short-form survey tools for gathering qualitative feedback at specific moments in the user journey, a spotlight-style command-palette search (activated with Cmd+K) that lets users find features or content without navigating menus, and AI-assisted content generation and A/B testing to help teams write and optimize in-app messaging faster. Built-in analytics report on how each tour, tooltip, or survey performs, including completion and interaction rates, so teams can iterate on onboarding flows based on actual usage data rather than guesswork. Chameleon's pricing follows a freemium structure: HelpBar, a lightweight Cmd+K-style in-app search and help widget, is free; the Startup plan starts at $279/month for smaller teams and lower monthly-active-user counts; the Growth plan starts at roughly $1,500/month on annual billing and adds capacity and features aimed at larger product organizations; and Enterprise pricing is custom, covering advanced security, support, and usage requirements for large companies. Pricing scales primarily with monthly active users and the specific mix of features, such as AI-powered tools or advanced targeting, a team needs, which is typical for the digital-adoption-platform category. Chameleon has raised early-stage venture funding to expand its platform beyond onboarding into what the company describes as a broader product-success or self-improving product system, aiming to cover the full loop of onboarding, engagement, feedback collection, and iteration rather than just first-run tours. It competes most directly with other digital adoption and product-led-growth platforms such as Pendo, WalkMe, and Userpilot. Chameleon is best suited to product and growth teams at SaaS companies who want to launch and iterate on in-app experiences themselves, without requiring a developer for every tour or survey change, and who have enough monthly active users to justify its per-MAU-scaled pricing; very early-stage products with small user bases may find the free HelpBar tier or the Startup plan sufficient before needing to move up to Growth or Enterprise tiers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0a6ea67e-e786-4158-b3c6-d8553bbb3f73';

