INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Personal Injury Case Tracking$q$, $q$Centralizes case timelines, tasks, and status for plaintiff personal injury matters in one shared workspace.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Medical Treatment & Lien Tracking$q$, $q$Tracks medical providers, treatment progress, and liens tied to each case to support demand and settlement preparation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Secure Client Portal & Online Intake$q$, $q$Lets prospective and current clients submit intake information and documents online through a branded, secure portal.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$eSignature Collection$q$, $q$Collects signatures on retainer agreements and case documents without leaving the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Legal AI Document Assistance$q$, $q$Uses built-in AI to help draft, summarize, and edit case documents and correspondence.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Reporting & Case Grades$q$, $q$Provides 50+ built-in reports plus a proprietary Case Grades score that flags case health and settlement readiness.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$SMS Text Communication$q$, $q$Sends and receives client text messages and appointment reminders directly from the case record on Pro and Advanced tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Data Sync & Integrations$q$, $q$Advanced-tier two-way data synchronization keeps CASEpeer aligned with other firm systems and third-party tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Purpose-built for personal injury practice, with treatment, lien, and settlement workflows other general legal software lacks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Tiered pricing with no long-term contract or setup fee$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$In-house support team providing free onboarding and ongoing training$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Built-in AI drafting and a 50+ report library reduce manual admin work$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Limited to personal injury workflows, so it is a poor fit for firms handling other practice areas$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Per-user pricing can get expensive for firms with larger support staff$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$No published self-serve free trial; evaluation requires a sales demo$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Higher-value features like texting, full reporting, and data sync are gated behind the Pro and Advanced tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$What does CASEpeer cost?$q$, $q$CASEpeer has three subscription tiers billed per user per month: Basic at $79, Pro at $119, and Advanced at $149, with no setup fee or long-term contract required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Is CASEpeer only for personal injury law firms?$q$, $q$Yes. CASEpeer is purpose-built for plaintiff-side personal injury practice, with case, medical treatment, lien, and settlement workflows tailored to that practice area rather than general legal matter management.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Does CASEpeer offer a free trial?$q$, $q$CASEpeer does not publicly advertise a self-serve free trial; prospective customers typically evaluate the platform through a scheduled product demo.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Where is CASEpeer hosted?$q$, $q$CASEpeer is a cloud-based platform hosted on Amazon Web Services with regular data backups, so firms do not need to install or maintain local servers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$What is included in the Advanced plan that isn't in Basic or Pro?$q$, $q$The Advanced plan adds text-message appointment scheduling, an office-wide reporting suite, a branded client intake portal, two-way data synchronization, and the Case Grades case-health scoring feature.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Does CASEpeer include AI features?$q$, $q$Yes, CASEpeer includes legal AI technology for drafting, summarizing, and editing case documents.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Personal Injury Intake-to-Settlement Workflow$q$, $q$Firms use CASEpeer to move a case from initial intake through medical treatment tracking, demand preparation, and settlement negotiation on a single shared record.$q$, $q$Personal injury law firms and plaintiff attorneys$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$High-Volume Caseload Management$q$, $q$Case managers and paralegals use Case Grades and built-in reporting to monitor dozens or hundreds of active cases and flag ones that need attention.$q$, $q$Paralegals and case managers at high-volume PI firms$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Basic$q$, $q$$79/user/month$q$, $q$Monthly$q$, NULL, $q$["Case and task tracking","Document management","Client portal","Online intake forms","eSignature"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Pro$q$, $q$$119/user/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Basic","Intake management automation","SMS texting","50+ built-in reports","Integration support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$Advanced$q$, $q$$149/user/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Pro","Text scheduling","Office reporting suite","Branded intake portal","Two-way data sync","Case Grades"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CASEpeer is case management software designed exclusively for personal injury law firms. Founded in 2015 and based in Irvine, California, the platform brings intake, documents, medical treatment tracking, and settlement workflows into one cloud-hosted system so paralegals, case managers, and attorneys can work from a shared, up-to-date case record.$q$, $q$Unlike general-purpose legal practice management tools, CASEpeer's data model is built around the specific rhythm of a plaintiff personal injury case: intake and liability assessment, medical treatment and lien tracking, demand package preparation, and settlement negotiation. Firms use it to standardize how cases move through that pipeline and to spot cases that are stalling or under-treated before they become a problem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every plan includes a secure client portal, online intake forms, document management, case and task tracking, and eSignature collection. Higher tiers add SMS-based client communication, an expanded library of over 50 pre-built reports, integrations with third-party practice tools, and CASEpeer's Advanced-tier additions: a public intake portal, two-way data synchronization with other systems, text-based appointment scheduling, and Case Grades, a scoring tool that flags case health and settlement readiness at a glance. CASEpeer also includes legal AI features for drafting, summarizing, and editing case documents, and the platform is hosted on Amazon Web Services with regular backups.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CASEpeer uses simple per-user, monthly subscription pricing with no setup fee or long-term contract: Basic at $79/user/month, Pro at $119/user/month, and Advanced at $149/user/month. Each tier is cumulative, with Pro and Advanced adding intake automation, communication, reporting, and data-sync capabilities on top of the Basic feature set. Pricing is not published for enterprise or multi-office arrangements, and prospective customers typically start with a scheduled product demo rather than a self-serve free trial.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2daef1f5-cac7-42ef-aa09-bc9e2945a78a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$ActivityPub / Fediverse Integration$q$, $q$Every hosted podcast is automatically a Fediverse account that Mastodon and similar network users can follow and comment on.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Podcasting 2.0 Support$q$, $q$Implements modern RSS namespace tags including transcripts, chapters, funding, soundbites, persons, and locked GUIDs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Self-Hosting & Data Ownership$q$, $q$Runs on infrastructure the podcaster controls, keeping media files, RSS feed, and listener data fully portable.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Multi-Platform Distribution$q$, $q$Publishes episodes to Apple Podcasts, Spotify, Google Podcasts, Deezer, Podcast Addict, and the Podcast Index.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Built-In Analytics$q$, $q$Tracks episode downloads and listening trends without relying on a third-party analytics service.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Plugin Architecture$q$, $q$Extends core functionality through community and first-party plugins rather than a locked feature set.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Free and open source with no license fee for self-hosting$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Combines full Podcasting 2.0 support with native ActivityPub/Fediverse features$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Full control over data, media files, and hosting infrastructure$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Active open-source development backed by a company (Ad Aures) rather than a single maintainer$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Self-hosting requires server administration knowledge or a paid managed-hosting provider$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Smaller ecosystem and support resources than large commercial podcast hosts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Managed Castopod.com hosting adds usage-based storage costs on top of the free base allowance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Fediverse and Podcasting 2.0 features have limited value if a show's audience uses only legacy podcast apps$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Is Castopod really free?$q$, $q$The Castopod software itself is free and open source under the AGPL-3.0 license. Self-hosting costs only what your server or hosting provider charges; Ad Aures' managed Castopod.com service adds a small usage-based fee for storage beyond the free allowance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$What is ActivityPub integration in Castopod?$q$, $q$Each podcast hosted on Castopod is automatically given a Fediverse (ActivityPub) account, so users on Mastodon and similar networks can follow the show and reply to episodes, with those replies appearing as comments in Castopod.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Can I self-host Castopod?$q$, $q$Yes. Castopod is open source and designed to be self-hosted on your own server, and it is also available through one-click hosting providers such as Elestio, Cloudron, and Klutch.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Does Castopod support Podcasting 2.0?$q$, $q$Yes, Castopod supports Podcasting 2.0 RSS tags including transcripts, chapters, funding, soundbites, persons, locations, and locked GUIDs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Who built Castopod?$q$, $q$Castopod is developed by Ad Aures, a French podcast technology company.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Self-Hosted Independent Podcasting$q$, $q$Independent podcasters and networks self-host Castopod to keep full ownership of their media, RSS feed, and audience data instead of using a proprietary host.$q$, $q$Independent podcasters and podcast networks$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Fediverse-Native Show Distribution$q$, $q$Shows that want listener interaction through Mastodon and other ActivityPub networks use Castopod to natively publish and receive comments from the Fediverse.$q$, $q$Podcasters engaging with Fediverse/open-social audiences$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Castopod software","Unlimited podcasts, subject to your own server capacity","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$Castopod.com Managed Hosting$q$, $q$Usage-based (~€0.06/GB storage)$q$, $q$Monthly$q$, NULL, $q$["Managed infrastructure","Free download allowance included","Custom domain support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Castopod is a free and open-source podcast hosting platform created by the French company Ad Aures. Released under the AGPL-3.0 license and built on the CodeIgniter4 PHP framework, it can be installed on any server the podcaster controls, deployed through one-click hosting providers, or accessed via Ad Aures' own managed hosting service at Castopod.com.$q$, $q$The platform is best known for pairing full Podcasting 2.0 support with native ActivityPub integration, making every hosted podcast a Fediverse account that listeners on Mastodon and similar networks can follow and comment on directly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Castopod supports the modern Podcasting 2.0 RSS tags — persistent GUIDs, locked feeds, transcripts, chapters, funding links, contributor/person tags, episode locations, and soundbites — and distributes episodes to Apple Podcasts, Spotify, Google Podcasts, Deezer, Podcast Addict, and the Podcast Index. Every podcast is also a native ActivityPub (Fediverse) account, so listeners can follow shows and reply to episodes from Mastodon or other federated networks, and those interactions display as comments inside Castopod. The platform includes built-in download analytics, a plugin architecture for extending functionality, and full data portability since self-hosted installations keep all media files and subscriber data under the podcaster's control.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Castopod's core software is free and open source with no license cost. Self-hosters pay only for their own server or a third-party managed-hosting provider's fee. Ad Aures also runs Castopod.com, a managed hosting option that includes a set number of free downloads per plan with additional bandwidth and storage billed at a small usage-based rate, letting creators avoid running their own infrastructure while still using the open-source platform.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9de517df-9167-4f74-81ef-57b4e421d271', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Unlimited Podcast Hosting$q$, $q$Hosts unlimited shows and episodes with no storage caps and no per-download overage fees within plan limits.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$WordPress Publishing (Seriously Simple Podcasting)$q$, $q$Publishes episodes directly from a WordPress dashboard using Castos' own WordPress plugin.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Multi-Platform Distribution$q$, $q$Automatically pushes new episodes to Apple Podcasts, Spotify, YouTube, and other major directories.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$AI Assistant$q$, $q$Generates show notes, episode titles, social posts, and chapter markers automatically from uploaded audio.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Private Podcast Feeds$q$, $q$Distributes gated audio for internal communications, employee onboarding, courses, or paid memberships.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Audience Analytics$q$, $q$Reports listener location, device type, and playback duration per episode.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$YouTube Republishing & Headliner Integration$q$, $q$Republishes episodes as YouTube videos and creates audiogram-style social clips on Growth tier and above.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Flat monthly pricing with no per-download overage fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Deep WordPress integration through the Seriously Simple Podcasting plugin$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$AI Assistant reduces manual show-notes and social-post production work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Supports private/internal podcast feeds in addition to public distribution$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Entry-tier download and transcription-credit limits may be restrictive for fast-growing shows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Video hosting and higher subscriber limits are gated behind the Pro and Premium tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Company headquarters and team structure are not clearly publicized, reflecting its fully remote operating model$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Entry pricing is higher than some no-frills podcast hosts$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$How much does Castos cost?$q$, $q$Castos has four tiers: Essentials at $19/month, Growth at $49/month, Pro at $99/month, and Castos Premium at $499/month, all with a 14-day free trial.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Does Castos integrate with WordPress?$q$, $q$Yes, Castos maintains the Seriously Simple Podcasting WordPress plugin, letting podcasters publish episodes directly from their WordPress site.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Can I republish podcast episodes to YouTube with Castos?$q$, $q$Yes, YouTube republishing is available starting on the Growth plan at $49/month and above.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Does Castos support private podcasts?$q$, $q$Yes, Castos supports private podcast feeds for internal company updates, course content, and paid membership audio, separate from public directory distribution.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Who founded Castos?$q$, $q$Castos was founded by Craig Hewitt, who continues to serve as its CEO.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$WordPress-Based Podcast Publishing$q$, $q$Podcasters who run their show's website on WordPress use Castos' plugin to publish episodes without leaving their WordPress dashboard.$q$, $q$WordPress-based podcasters and bloggers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Agency & Multi-Client Podcast Management$q$, $q$Podcast production agencies use Castos to host and manage shows for multiple clients from a single account.$q$, $q$Podcast production agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Private/Internal Podcasting$q$, $q$Companies and course creators use Castos' private feeds to distribute gated audio for onboarding, internal updates, or paid content.$q$, $q$Internal comms teams and online course creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Essentials$q$, $q$$19/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited shows and episodes","Up to 100 private subscribers","~20,000 monthly downloads","10 transcription credits/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Growth$q$, $q$$49/month$q$, $q$Monthly$q$, NULL, $q$["Up to 250 private subscribers","~75,000 monthly downloads","25 transcription credits/month","YouTube republishing","Headliner integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Pro$q$, $q$$99/month$q$, $q$Monthly$q$, NULL, $q$["Up to 500 private subscribers","~200,000 monthly downloads","100 transcription credits/month","Video file hosting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$Castos Premium$q$, $q$$499/month$q$, $q$Monthly$q$, NULL, $q$["Custom contracts and invoicing","Single sign-on","Increased usage limits","Dedicated account manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Castos is a podcast hosting platform founded by Craig Hewitt in 2016 that grew out of the WordPress podcasting plugin ecosystem. It hosts unlimited episodes and shows for a flat monthly fee, with no per-download overage charges within a plan's included limits.$q$, $q$The platform is particularly known for its WordPress integration through the Seriously Simple Podcasting plugin, which lets podcasters publish new episodes directly from their WordPress dashboard, and for supporting agencies that manage podcasts for multiple clients from one account.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Castos automatically distributes new episodes to Apple Podcasts, Spotify, YouTube, and other major directories, and includes audience analytics covering listener location, device, and per-episode playback duration. A built-in AI Assistant turns uploaded audio into show notes, episode titles, social posts, and chapter markers. Growth-tier and above add YouTube republishing and Headliner integration for creating audiogram-style social clips, while the Pro tier adds video file hosting. Castos also supports private podcast feeds for internal company communications, course content, or paid membership audio, and provides a customizable podcast website that requires no design or development work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Castos offers four tiers, all billed monthly with a 14-day free trial: Essentials at $19/month, Growth at $49/month, Pro at $99/month, and Castos Premium at $499/month for larger teams needing single sign-on, custom contracts, and a dedicated account manager. Each tier raises the included private-subscriber count, monthly download allowance, and transcription credits, and unlocks additional features like YouTube republishing, video hosting, and enterprise account management.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1be06e6f-80c4-4800-be23-0b5ae2f639dd', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Interactive Gantt Charts$q$, $q$Visualizes project schedules with critical-path highlighting to spot potential delays before they happen.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Resource Management$q$, $q$Plans and balances team capacity across projects with resource allocation and utilization views.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Built-In Time Tracking$q$, $q$Logs hours directly against tasks for accurate project time and cost reporting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Advanced Analytics & What-If Scenarios$q$, $q$Runs trend analysis and scenario forecasting to model the impact of schedule or resource changes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Customizable Dashboards & Reporting$q$, $q$Provides in-depth, configurable reports and dashboards for portfolio-level visibility.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Cloud or On-Premise Deployment$q$, $q$Runs as hosted SaaS or as a self-managed on-premise install on Linux and PostgreSQL.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Client Portal & Billing$q$, $q$Business-tier plans include a free client portal plus project billing and invoicing tools.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Rare dual cloud/on-premise deployment option among modern project management tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Deep analytics with trend analysis and what-if scenario modeling$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Two decades of operating history with Fortune 500 and PMO customers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Granular per-role pricing (Team-Member, Timesheet users) can lower cost for mixed teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Five full-access-user minimum makes it less accessible for very small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Interface and reporting depth can have a steeper learning curve than lighter task-management tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Advanced features like risk tracking, billing, and client portal require upgrading to Professional or Business tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$On-premise deployment requires in-house Linux/PostgreSQL administration capability$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$How much does Celoxis cost?$q$, $q$Celoxis pricing starts at $10/user/month for the Core plan and scales through Essentials ($25), Professional ($35), and Business ($45) tiers, billed annually with a five-user minimum; Enterprise is custom-priced.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Can Celoxis be self-hosted?$q$, $q$Yes. In addition to its cloud SaaS product, Celoxis offers an on-premise deployment option that runs on Linux and PostgreSQL.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$What is Celoxis' best-value plan?$q$, $q$Celoxis positions its Professional tier ($35/user/month), which adds risk tracking, intake management, and project costing, as its best-value plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Does Celoxis integrate with other tools?$q$, $q$Yes, Celoxis offers add-on integrations with tools including JIRA, Azure DevOps, and QuickBooks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Who uses Celoxis?$q$, $q$Celoxis is used by PMOs and project teams at organizations ranging from mid-size businesses to Fortune 500 companies for portfolio and project management.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Enterprise Portfolio & PMO Management$q$, $q$PMOs use Celoxis' analytics, dashboards, and what-if scenarios to plan and monitor portfolios of projects across an organization.$q$, $q$PMOs and enterprise project management teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Data-Sensitive On-Premise Deployment$q$, $q$Organizations with data residency or security requirements install Celoxis on-premise instead of using a cloud-only alternative.$q$, $q$Regulated or security-conscious enterprises$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Core$q$, $q$$10/user/month$q$, $q$Annual$q$, NULL, $q$["Basic project tracking","Reports and dashboards","Gantt charts","2 free read-only users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Essentials$q$, $q$$25/user/month$q$, $q$Annual$q$, NULL, $q$["Everything in Core","Timesheets","Job roles","Resource planning","5 free read-only users"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Professional$q$, $q$$35/user/month$q$, $q$Annual$q$, NULL, $q$["Everything in Essentials","Risk tracking","Intake management","Project costing","10 free read-only users"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Business$q$, $q$$45/user/month$q$, $q$Annual$q$, NULL, $q$["Everything in Professional","Billing/invoicing","Free client portal","Advanced security","15 free read-only users"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Tailored for large teams and complex needs","Custom limits and support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Celoxis is project management and PMO software built by Celoxis Technologies, founded in 2001 and headquartered in Pune, India. With more than two decades in the category, Celoxis is used by Fortune 500 companies and PMOs for both portfolio-level planning and day-to-day task management.$q$, $q$A key differentiator is deployment flexibility: Celoxis is available as a cloud SaaS product or as an on-premise installation on Linux and PostgreSQL, which appeals to organizations with data residency or security requirements that rule out cloud-only project management tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Celoxis centers on interactive Gantt charts with critical-path visibility, resource management and capacity planning, and time tracking built directly into task records. Its analytics layer includes trend analysis and what-if scenario modeling, letting PMOs forecast the impact of schedule or staffing changes before making them. Reporting is a particular strength, with customizable dashboards and report builders aimed at portfolio-level visibility rather than single-project views. Higher tiers add risk tracking, project costing and billing, a free client portal, and advanced security controls, and the platform integrates with tools like JIRA, Azure DevOps, and QuickBooks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Celoxis prices per user per month, billed annually, with a five full-access-user minimum. Core starts at $10/user/month with basic tracking, reports, and Gantt charts; Essentials ($25), Professional ($35), and Business ($45) progressively add timesheets and resource planning, risk tracking and costing, and billing/client-portal/security features respectively; Enterprise is custom-priced for large deployments. Reduced-rate Team-Member and Timesheet user roles are available on Essentials and above for staff who need limited rather than full project-management access.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c59b3c9-1d5c-41aa-8b9d-d87093081798', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Multi-Transport Pub/Sub$q$, $q$Delivers real-time messages over WebSocket, HTTP-streaming, Server-Sent Events, WebTransport, and gRPC.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Horizontal Scaling$q$, $q$Scales across a cluster using Redis, Redis-compatible stores, PostgreSQL, or NATS as the coordination layer.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Channel History & Recovery$q$, $q$Stores channel history and automatically recovers missed messages after a client disconnects and reconnects.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Presence Tracking$q$, $q$Reports which clients are currently subscribed to a channel in real time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Backend Event Proxying$q$, $q$Proxies connection and subscription events to an application's own backend for custom authorization logic.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Broad SDK Coverage$q$, $q$Provides official client libraries for JavaScript, React Native, Dart/Flutter, Swift, Java, Python, Go, and .NET.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Free, Apache 2.0-licensed core with no per-connection or per-message fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Production-proven at scale by companies including VK, Badoo, ManyChat, and Grafana$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Supports multiple transports and scaling backends rather than locking teams into one stack$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Broad official SDK coverage across web, mobile, and backend languages$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Requires engineering effort to deploy, secure, and integrate versus a plug-and-play hosted API$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Centrifugo PRO pricing is not publicly listed, requiring direct contact for enterprise features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Self-hosted operation means the adopting team is responsible for uptime, scaling, and monitoring$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$No official company headquarters or large support organization behind the open-source core$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Is Centrifugo free to use?$q$, $q$Yes. Centrifugo's core server is open source under the Apache 2.0 license and free to self-host. A paid Centrifugo PRO edition with additional enterprise features is also available.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$What can Centrifugo be used for?$q$, $q$Common use cases include chat applications, live comment feeds, multiplayer game state sync, real-time dashboards, collaborative tools, and streaming AI/LLM responses to clients as they're generated.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$How does Centrifugo scale?$q$, $q$Centrifugo scales horizontally across a cluster using Redis (or Redis-compatible stores), PostgreSQL, or NATS to coordinate state between nodes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$What transports does Centrifugo support?$q$, $q$Centrifugo supports WebSocket, HTTP-streaming, Server-Sent Events, WebTransport, and gRPC.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Who maintains Centrifugo?$q$, $q$Centrifugo is maintained by Alexander Emelin and the Centrifugal Labs project.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$In-App Chat & Live Comments$q$, $q$Development teams use Centrifugo to power real-time chat and live comment features without depending on a hosted third-party API.$q$, $q$Backend and full-stack engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$AI Response Streaming$q$, $q$Applications use Centrifugo to stream partial LLM/AI responses to clients as they are generated.$q$, $q$Teams building AI-powered products$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Open Source (Apache 2.0)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full self-hosted server","All core transports and scaling backends","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$Centrifugo PRO$q$, $q$Custom$q$, $q$N/A$q$, NULL, $q$["Additional enterprise-oriented features","Commercial support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Centrifugo is an open-source, self-hosted real-time messaging server built by developer Alexander Emelin under the Centrifugal Labs project. Written in Go, it began as an earlier Python tool called Centrifuge around 2012 before being rewritten and established as Centrifugo around 2015, and it is released under the Apache 2.0 license.$q$, $q$Centrifugo is designed as a self-hosted alternative to hosted real-time APIs such as Pusher, Ably, PubNub, and Socket.IO. Instead of paying a third-party service per connection or message, teams run Centrifugo on their own infrastructure and connect it to their existing authentication and backend systems.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Centrifugo exposes a channel-based publish/subscribe model over WebSocket, HTTP-streaming, Server-Sent Events, WebTransport, and gRPC, so clients can pick whichever transport suits their environment. It supports channel history with automatic stream recovery after disconnects, online presence tracking, delta-compressed updates to cut bandwidth, and the ability to proxy connection and subscription events to an application's own backend for custom authorization. For scaling, Centrifugo coordinates cluster state through Redis, Redis-compatible stores, PostgreSQL, or NATS, and the project reports that a single modern server can handle around one million concurrent WebSocket connections and roughly thirty million delivered messages per minute. Official SDKs cover JavaScript, React Native, Dart/Flutter, Swift, Java, Python, Go, and .NET.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Centrifugo's core server is free and open source under the Apache 2.0 license, with no cost to self-host at any scale. Centrifugal Labs also sells Centrifugo PRO, a paid edition with additional enterprise-oriented features; PRO pricing is not publicly listed and is quoted on request, so cost beyond infrastructure depends on whether a team needs the open-source core or the commercial PRO edition.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c38ae10-51dd-4efa-aae5-4c2f20863745', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Unified Object, Block, and File Storage$q$, $q$Serves S3/Swift-compatible object storage, block storage (RBD), and a POSIX filesystem (CephFS) from one cluster.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$No Single Point of Failure$q$, $q$Distributes and replicates data across nodes using the CRUSH algorithm, so the cluster tolerates node and disk failures.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Exabyte-Scale Growth$q$, $q$Scales horizontally on commodity hardware without requiring proprietary storage appliances.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Self-Healing & Self-Managing$q$, $q$Automatically detects failures and rebalances data across the cluster with minimal manual administration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$BlueStore Backend$q$, $q$Manages raw block devices directly for improved performance instead of relying on a conventional filesystem.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$OpenStack & Kubernetes Integration$q$, $q$Commonly used as the storage layer under OpenStack clouds and Kubernetes persistent volumes via the Rook operator.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Free and open source with no software license cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Proven at large scale, backed by Red Hat's ongoing development investment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Unifies object, block, and file storage in a single cluster instead of separate systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Runs on standard commodity hardware rather than proprietary storage appliances$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Requires significant in-house expertise to deploy, tune, and operate reliably at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Enterprise support via Red Hat Ceph Storage has pricing that is not publicly listed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Not designed for small-scale or single-node use cases where simpler storage would suffice$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Cluster rebalancing and recovery operations can be resource-intensive on large deployments$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Is Ceph free to use?$q$, $q$Yes, Ceph is free and open source under the LGPL 2.1 license. Red Hat sells an optional commercial-support distribution, Red Hat Ceph Storage, for organizations that want enterprise support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Who created Ceph?$q$, $q$Ceph was created by Sage Weil as part of his doctoral research at the University of California, Santa Cruz, and was first open-sourced in 2006.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$What storage types does Ceph support?$q$, $q$Ceph provides object storage (S3/Swift-compatible via RADOS Gateway), block storage (RBD), and a POSIX-compliant distributed filesystem (CephFS) from a single cluster.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$How does Ceph avoid a single point of failure?$q$, $q$Ceph replicates or erasure-codes data across cluster nodes using the CRUSH placement algorithm, which calculates data location without relying on a central metadata lookup.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$What is Red Hat's relationship to Ceph?$q$, $q$Red Hat acquired Inktank, the company that provided commercial support for Ceph, in 2014, and has since led much of Ceph's core development while also selling an enterprise-supported distribution.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Private & Hybrid Cloud Storage$q$, $q$Enterprises and cloud providers use Ceph as the storage backend for OpenStack clouds and Kubernetes persistent volumes.$q$, $q$Cloud providers and enterprise infrastructure teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$Large-Scale Research & Archival Storage$q$, $q$Research institutions use Ceph to store and preserve large datasets at petabyte-to-exabyte scale on commodity hardware.$q$, $q$Research institutions and data archives$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ceph is a free and open-source, software-defined storage platform that unifies object, block, and file storage on a single distributed cluster. It originated as Sage Weil's doctoral research at UC Santa Cruz and was first open-sourced in 2006 under the LGPL 2.1 license.$q$, $q$Red Hat acquired Inktank, the company Weil co-founded to support Ceph, in 2014, and has since driven much of the project's core development while Ceph remains community-governed under the Ceph Foundation and the Linux Foundation. Red Hat also sells an enterprise-supported distribution, Red Hat Ceph Storage.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ceph distributes and replicates (or erasure-codes) data across cluster nodes using the CRUSH placement algorithm, avoiding both a single point of failure and a central metadata bottleneck, which lets it scale to exabyte-level capacity on commodity hardware. Since the Luminous release, Ceph has managed raw storage devices directly through its own BlueStore backend rather than relying on a conventional filesystem. It exposes three interfaces from one cluster: the RADOS Gateway for S3/Swift-compatible object storage, RADOS Block Device (RBD) for block storage commonly backing virtual machines and containers, and CephFS, a POSIX-compliant distributed filesystem. The system is designed to be self-healing and self-managing, automatically detecting failures and rebalancing data with minimal manual intervention.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32f17210-2418-4e31-bedc-836e12407246', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ceph the software is free and open source with no license fee under the LGPL 2.1 license. Organizations that want commercial support, certified releases, and enterprise tooling can purchase Red Hat Ceph Storage, whose subscription pricing is not publicly listed and is quoted directly by Red Hat. Otherwise, the primary cost of running Ceph is infrastructure and the in-house expertise needed to deploy and operate a distributed storage cluster.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('32f17210-2418-4e31-bedc-836e12407246', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('32f17210-2418-4e31-bedc-836e12407246', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('32f17210-2418-4e31-bedc-836e12407246', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Policy Decision Point (PDP)$q$, $q$Evaluates YAML-defined authorization policies against requests and returns allow/deny decisions with sub-millisecond latency.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Multiple Access-Control Models$q$, $q$Supports RBAC, ABAC, ReBAC, and PBAC out of the box rather than locking teams into one model.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Language-Agnostic SDKs$q$, $q$Provides official SDKs for Go, Java, JavaScript, Python, .NET, PHP, Ruby, and Rust.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Cerbos Hub$q$, $q$Commercial control plane for policy authoring, testing, versioning, distribution, and audit visibility.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Synapse Data Enrichment$q$, $q$Pulls identity, resource, and relationship data from external systems to enrich authorization decisions, including for AI agent access.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Stateless, Horizontally Scalable Architecture$q$, $q$Runs as a stateless Go service that scales horizontally across infrastructure.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Open-source PDP is free to self-host indefinitely under Apache 2.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Supports RBAC, ABAC, ReBAC, and PBAC models rather than a single fixed model$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Sub-millisecond decision latency suited to high-throughput applications$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Cerbos Hub adds policy testing, versioning, and audit trails without giving up the open-source core$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Production-tier Cerbos Hub pricing starting at $933/month is a significant jump from the Development tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Requires engineering investment to model application resources and actions as Cerbos policies$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Open-core model means some governance and audit features are commercial-only$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Relatively young company, founded in 2021, compared to some established authorization and IAM vendors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Is Cerbos free?$q$, $q$The Cerbos Policy Decision Point (PDP) is open source under Apache 2.0 and free to self-host indefinitely. Cerbos Hub, the commercial policy-management layer, has a free tier plus paid Development, Production, and Enterprise tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$What access-control models does Cerbos support?$q$, $q$Cerbos supports role-based (RBAC), attribute-based (ABAC), relationship-based (ReBAC), and general policy-based (PBAC) access control out of the box.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$How much does Cerbos Hub cost?$q$, $q$Cerbos Hub starts free for up to 100 monthly active principals, with a Development tier from $25/month, a Production tier from $933/month, and custom Enterprise pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$What languages does Cerbos support?$q$, $q$Cerbos provides official SDKs for Go, Java, JavaScript, Python, .NET, PHP, Ruby, and Rust.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Who founded Cerbos and where is it based?$q$, $q$Cerbos was founded in 2021 by Emre Baran, Alex Olivier, and Charith Ellawala, and is headquartered in London, United Kingdom.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$What is Cerbos Synapse?$q$, $q$Synapse is a Cerbos component that fetches identity, resource, and relationship data from external systems to enrich authorization requests, including for governing what AI agents can access.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Fine-Grained SaaS Authorization$q$, $q$Multi-tenant SaaS applications use Cerbos to manage complex, per-resource permission logic outside their application code.$q$, $q$Engineering teams building multi-tenant SaaS products$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$AI Agent Access Control$q$, $q$Teams use Cerbos and Synapse to define and audit exactly what internal systems and data AI agents are permitted to access.$q$, $q$Teams deploying AI agents against internal systems$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$PDP (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted policy decision point","YAML-based policies","Audit logs","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Hub - Proof of Concept$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["Up to 100 monthly active principals","1 workspace, 2 developers","2 simultaneous PDPs","1 week audit log retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Hub - Development$q$, $q$From $25/month$q$, $q$Monthly$q$, NULL, $q$["First 100 monthly active principals included","3 workspaces, 5 developers","10 simultaneous PDPs","3 months audit log retention","Uptime SLA"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Hub - Production$q$, $q$From $933/month$q$, $q$Monthly$q$, NULL, $q$["First 5,000 monthly active principals included","Unlimited workspaces and developers","Unlimited PDPs and tenants","1 year audit log retention"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$Hub - Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["SSO support","Self-hosted Hub option","Custom audit retention","Enterprise SLA and training"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cerbos is an open-source, language-agnostic authorization engine founded in 2021 by Emre Baran, Alex Olivier, and Charith Ellawala, and headquartered in London, United Kingdom. It lets development teams move access-control logic out of application code and into centrally managed policies.$q$, $q$Teams write authorization rules as YAML policies defining who can perform which actions on which resources; the Cerbos Policy Decision Point (PDP) evaluates those policies against each incoming request and returns an allow or deny decision, decoupling permission logic from the rest of the codebase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Cerbos PDP is open source under Apache 2.0, written in Go for stateless, horizontally scalable deployment, and evaluates authorization requests with sub-millisecond latency. It supports RBAC, ABAC, ReBAC, and PBAC access-control models out of the box and ships official SDKs for eight languages, including Go, Java, JavaScript, Python, .NET, PHP, Ruby, and Rust. On top of the open-source PDP, Cerbos Hub adds a commercial control plane for policy authoring, testing, versioning, distribution, and audit visibility, and Synapse enriches authorization requests with identity, resource, and relationship data pulled from external systems — including for controlling what AI agents can access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Cerbos PDP is free to self-host indefinitely under Apache 2.0. Cerbos Hub, the commercial policy-management layer, has a free Proof of Concept tier (up to 100 monthly active principals), a Development tier starting at $25/month with a three-month free trial, a Production tier starting at $933/month covering the first 5,000 monthly active principals, and a custom-priced Enterprise tier with SSO, self-hosted Hub, and extended audit retention.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('62db09f8-596e-4759-92a2-df735f8464c1', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$No-Code In-App Tours & Tooltips$q$, $q$Builds interactive product tours, tooltips, and hotspots without writing code or waiting on engineering.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Announcement Banners & Checklists$q$, $q$Announces new features and guides users through setup with banners and step-by-step checklists.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$NPS & Microsurveys$q$, $q$Collects in-product feedback through native NPS and short-form surveys triggered at specific moments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$HelpBar (Cmd+K Search)$q$, $q$Provides a spotlight-style command-palette search so users can find features or help content instantly.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$AI-Powered Content & A/B Testing$q$, $q$Uses AI to help generate in-app messaging and run experiments to optimize onboarding and engagement flows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Embeddable Components$q$, $q$Places interactive UI elements anywhere in a product's interface through an embeddable component system.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Engagement Analytics$q$, $q$Reports completion and interaction rates for every tour, tooltip, and survey to guide iteration.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$No-code editor lets product and growth teams launch changes without engineering dependency$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Free HelpBar tier provides an entry point before committing to a paid plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Covers the full loop of onboarding, feature adoption, and feedback collection in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$AI-assisted content generation and A/B testing speed up experimentation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Paid plans starting at $279/month and scaling into the thousands can be costly for early-stage products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Pricing scales with monthly active users, so cost grows as a product's user base grows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Growth-tier pricing around $1,500/month requires annual billing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$As with most digital adoption platforms, poorly designed tours or surveys can still frustrate users if overused$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Is Chameleon free?$q$, $q$Chameleon's HelpBar (Cmd+K in-app search and help widget) is free. Full product-adoption features require a paid plan starting at $279/month (Startup).$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$How much does Chameleon cost?$q$, $q$Chameleon's paid plans start with Startup at $279/month, Growth from roughly $1,500/month on annual billing, and custom-priced Enterprise plans for large organizations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Do I need a developer to use Chameleon?$q$, $q$No. Chameleon is a no-code platform, letting product, marketing, and customer success teams build and launch in-app tours, tooltips, and surveys without writing code.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Who founded Chameleon?$q$, $q$Chameleon was founded in 2015 by Pulkit Agrawal and Brian Norton, and is headquartered in San Francisco, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$What is HelpBar?$q$, $q$HelpBar is Chameleon's free, Cmd+K-style in-app search and help widget that lets users find features or content instantly.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$What are Chameleon's main competitors?$q$, $q$Chameleon competes most directly with other digital adoption and product-led-growth platforms such as Pendo, WalkMe, and Userpilot.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$New User Onboarding$q$, $q$Product teams use Chameleon's tours and checklists to guide new users to their first value moment without engineering involvement.$q$, $q$Product and growth teams at SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Feature Adoption & Announcements$q$, $q$Teams use tooltips, hotspots, and banners to drive adoption of new or underused features among existing users.$q$, $q$Product marketing and product-led-growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$In-Product Feedback Collection$q$, $q$Customer success and product teams deploy NPS and microsurveys at key moments to gather feedback without leaving the product.$q$, $q$Customer success and product research teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$HelpBar$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Cmd+K in-app search and help widget"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Startup$q$, $q$From $279/month$q$, $q$Monthly$q$, NULL, $q$["In-app tours, tooltips, and banners","Basic surveys","Engagement analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Growth$q$, $q$From $1,500/month$q$, $q$Annual$q$, NULL, $q$["Everything in Startup","AI-powered tools","A/B testing","Higher MAU limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Advanced security and support","Custom MAU limits","Dedicated onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chameleon is a no-code digital adoption platform founded in 2015 by Pulkit Agrawal and Brian Norton and headquartered in San Francisco, California. It lets product, marketing, and customer success teams build in-app user experiences without writing code or relying on engineering resources for every change.$q$, $q$The platform is aimed at product-led-growth use cases: user onboarding, feature announcements and adoption, upsell prompts, and in-product feedback collection, letting non-technical teams launch and iterate on these experiences directly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Chameleon's building blocks include in-app tours, tooltips, hotspots, and announcement banners built through an embeddable, no-code component system; native NPS and short-form microsurveys for gathering feedback at specific moments in the user journey; a spotlight-style Cmd+K search/help bar (HelpBar) that lets users find features or answers without navigating menus; and AI-powered tools for generating in-app content and running A/B tests. Built-in analytics track how each tour, tooltip, or survey performs — including completion and interaction rates — so teams can iterate based on real usage data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a6ea67e-e786-4158-b3c6-d8553bbb3f73', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Chameleon follows a freemium model. HelpBar, its Cmd+K-style in-app search and help widget, is free. Paid plans start with Startup at $279/month, scale to Growth from roughly $1,500/month on annual billing, and top out with custom-priced Enterprise plans for large organizations with advanced security, support, and scale requirements. Pricing scales primarily with monthly active users and the feature set, including AI tools, a team needs.$q$]::text[], 2);
